{
  "safetyAssessment": {
    "level": "caution",
    "concerns": [
      "A 600-calorie-per-meal warning threshold is very low and could reinforce restrictive eating patterns.",
      "Repeated low-calorie alerts may encourage undereating, which carries health risks.",
      "The framing 'cut down harder' suggests a potentially punishing relationship with food."
    ],
    "userMessage": "I can build this for you, but I want to flag a care note first: 600 calories is a quite low threshold for a single meal warning, and alert-based restriction can sometimes make our relationship with food feel more stressful rather than healthier. The tracker below is built neutrally — it logs meals and notes when a meal is above your chosen threshold — but I'd encourage you to set a threshold that reflects balanced, sustainable eating rather than maximum restriction. If you're working with a doctor or dietitian, their guidance on targets is a great anchor for the number you use."
  },
  "type": {
    "typeId": "meal_entry",
    "displayName": "Meal Entry",
    "displayNamePlural": "Meal Entries",
    "description": "A log of a meal or snack, including calorie content and optional notes.",
    "examplePhrases": [
      "Log my lunch",
      "I just ate breakfast",
      "Add a snack entry",
      "Record what I had for dinner",
      "Track my meal calories"
    ],
    "attributes": [
      {
        "name": "mealName",
        "label": "Meal / Snack",
        "valueType": "text",
        "required": true
      },
      {
        "name": "mealType",
        "label": "Meal Type",
        "valueType": "enum",
        "enumValues": ["Breakfast", "Lunch", "Dinner", "Snack", "Other"],
        "required": false
      },
      {
        "name": "calories",
        "label": "Calories (kcal)",
        "valueType": "number",
        "required": true
      },
      {
        "name": "warningThreshold",
        "label": "Personal Warning Threshold (kcal)",
        "valueType": "number",
        "required": false
      },
      {
        "name": "loggedAt",
        "label": "Logged At",
        "valueType": "datetime",
        "required": true,
        "defaultToNow": true
      },
      {
        "name": "loggedDate",
        "label": "Date",
        "valueType": "date",
        "required": false
      },
      {
        "name": "thresholdExceeded",
        "label": "Threshold Exceeded",
        "valueType": "boolean",
        "required": false
      },
      {
        "name": "notes",
        "label": "Notes",
        "valueType": "text",
        "required": false
      },
      {
        "name": "foods",
        "label": "Foods / Ingredients",
        "valueType": "tag",
        "required": false
      }
    ],
    "relations": [],
    "presentation": {
      "archetype": "log",
      "primaryField": "mealName"
    }
  },
  "skill": {
    "skillId": "log-meal-with-threshold-check",
    "displayName": "Log Meal & Check Calorie Threshold",
    "inputs": [
      { "name": "mealName", "valueType": "text", "source": "slot", "required": true },
      { "name": "calories", "valueType": "number", "source": "slot", "required": true },
      { "name": "mealType", "valueType": "text", "source": "slot", "required": false },
      { "name": "notes", "valueType": "text", "source": "slot", "required": false },
      { "name": "warningThreshold", "valueType": "number", "source": "slot", "required": false },
      { "name": "userDefinedThreshold", "valueType": "number", "source": "system", "required": false }
    ],
    "reads": ["meal_entry"],
    "writes": ["meal_entry"],
    "dangerLevel": "safe",
    "steps": {
      "main": [
        {
          "id": "resolve_threshold",
          "op": "compute",
          "expr": "if(warningThreshold, warningThreshold, if(userDefinedThreshold, userDefinedThreshold, 600))",
          "into": "effectiveThreshold"
        },
        {
          "id": "check_exceeded",
          "op": "compute",
          "expr": "if(calories > effectiveThreshold, true, false)",
          "into": "exceeded"
        },
        {
          "id": "get_date",
          "op": "compute",
          "expr": "today()",
          "into": "todayDate"
        },
        {
          "id": "save_entry",
          "op": "write_record",
          "typeId": "meal_entry",
          "data": {
            "mealName": "{{mealName}}",
            "calories": "{{calories}}",
            "mealType": "{{mealType}}",
            "notes": "{{notes}}",
            "warningThreshold": "{{effectiveThreshold}}",
            "thresholdExceeded": "{{exceeded}}",
            "loggedDate": "{{todayDate}}"
          },
          "into": "savedEntry"
        },
        {
          "id": "branch_exceeded",
          "op": "branch",
          "condition": "exceeded",
          "then": [
            {
              "id": "compute_over_by",
              "op": "compute",
              "expr": "calories - effectiveThreshold",
              "into": "overBy"
            },
            {
              "id": "format_warning",
              "op": "format",
              "template": "⚠️ Heads-up: '{{mealName}}' was logged at {{calories}} kcal — {{overBy}} kcal over your {{effectiveThreshold}} kcal threshold. Meal saved. Remember: consistent, balanced eating supports long-term wellbeing.",
              "into": "resultMessage"
            }
          ],
          "else": [
            {
              "id": "format_ok",
              "op": "format",
              "template": "✅ '{{mealName}}' logged at {{calories}} kcal — within your {{effectiveThreshold}} kcal threshold.",
              "into": "resultMessage"
            }
          ]
        },
        {
          "id": "set_output",
          "op": "set",
          "key": "output",
          "value": "{{resultMessage}}"
        }
      ]
    }
  }
}
